translated_files.mix_kernels.cl:
#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

inline class_T mix_op(class_T x, class_T seed) {
  return x * x + seed;
}

__kernel void benchmark_func(const class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);

#ifndef BLOCK_STRIDED
  const size_t base = gid * (size_t)(ELEMENTS_PER_THREAD * FUSION_DEGREE);

  for (uint f = 0; f < (uint)FUSION_DEGREE; ++f) {
    const size_t fbase = base + (size_t)f * (size_t)ELEMENTS_PER_THREAD;
    for (uint e = 0; e < (uint)ELEMENTS_PER_THREAD; ++e) {
      const size_t idx = fbase + (size_t)e;
      class_T t = data[idx];
      for (uint it = 0; it < (uint)COMPUTE_ITERATIONS; ++it) {
        t = mix_op(t, seed);
      }
      data[idx] = t;
    }
  }

#else
  const size_t lid = get_local_id(0);
  const size_t lsz = get_local_size(0);
  const size_t group = get_group_id(0);
  const size_t group_span = lsz * (size_t)(ELEMENTS_PER_THREAD * FUSION_DEGREE);
  const size_t group_base = group * group_span;

  for (uint f = 0; f < (uint)FUSION_DEGREE; ++f) {
    const size_t fbase = group_base + (size_t)f * lsz * (size_t)ELEMENTS_PER_THREAD;
    for (uint e = 0; e < (uint)ELEMENTS_PER_THREAD; ++e) {
      const size_t idx = fbase + (size_t)e * lsz + lid;
      class_T t = data[idx];
      for (uint it = 0; it < (uint)COMPUTE_ITERATIONS; ++it) {
        t = mix_op(t, seed);
      }
      data[idx] = t;
    }
  }
#endif
}
